# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>

// n=200 boxes, m=10 stacks, each stack starts with 20 boxes
// Extract boxes in order 1..n. Moving k boxes costs k+1 energy.
// Score = max(1, 10000 - total_energy). Maximize score = minimize energy.

const double TIME_LIMIT_SECONDS = 1.90;
auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) { return std::uniform_int_distribution<int>(lo, hi)(rng); }
    double randdbl() { return std::uniform_real_distribution<double>(0.0, 1.0)(rng); }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    std::vector<std::vector<int>> stacks; // stacks[i] = boxes from bottom to top, 0-indexed
    std::vector<int> box_stack; // which stack each box is in
    std::vector<int> box_height; // position within the stack
    int N, M;
    long long energy;

    State() : N(0), M(0), energy(0) {}

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks) {
        N = n; M = m; energy = 0;
        stacks.resize(M);
        box_stack.resize(N);
        box_height.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    // Move box v and everything above it to dest stack
    void move(int v, int dest) {
        int src = box_stack[v];
        int h = box_height[v];
        int num_moved = (int)stacks[src].size() - h;
        energy += num_moved + 1;
        int dest_base = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_height[b] = dest_base + (i - h);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(h);
    }

    // Carry out box v (must be on top of its stack)
    void carry_out(int v) {
        int src = box_stack[v];
        stacks[src].pop_back();
    }

    bool is_on_top(int v) const {
        int src = box_stack[v];
        return box_height[v] == (int)stacks[src].size() - 1;
    }

    int boxes_above(int v) const {
        int src = box_stack[v];
        return (int)stacks[src].size() - 1 - box_height[v];
    }
};

// Heuristic: estimate how "costly" a state will be for upcoming extractions
// Lower is better
double heuristic_future_cost(const State& s, int next_target, int lookahead) {
    double cost = 0.0;
    int end = std::min(next_target + lookahead, s.N);
    for (int v = next_target; v < end; v++) {
        int above = s.boxes_above(v);
        if (above > 0) {
            cost += above + 1.0;
        }
    }
    return cost;
}

// Evaluate placing a block on a destination stack
// block = boxes from bottom to top that will be placed on dest
// next_target = the next box to be extracted after current operation
double evaluate_placement(const State& s, const std::vector<int>& block, int dest, int next_target, int lookahead) {
    double score = 0.0;
    int W = lookahead;

    // Penalty for covering boxes in dest that are needed soon
    const auto& dest_stack = s.stacks[dest];
    for (int b : dest_stack) {
        if (b >= next_target && b < next_target + W) {
            // This box is needed soon and we're covering it with block.size() more boxes
            score += (double)(block.size() + 1) * 3.0;
        }
    }

    // Penalty for boxes in the block that are needed soon and will be deep
    for (int i = 0; i < (int)block.size(); i++) {
        int b = block[i];
        if (b >= next_target && b < next_target + W) {
            // This needed-soon box will be at position (dest_stack.size() + i) in the new stack
            // Boxes above it in the placed block: block.size() - 1 - i
            int boxes_on_top = (int)block.size() - 1 - i;
            score += (double)(boxes_on_top + 1) * 2.5;
        }
    }

    // Prefer emptier stacks slightly (good for buffer)
    score += (double)dest_stack.size() * 0.1;

    // Bonus for placing on stack where min label is high (they won't be needed soon)
    // i.e., avoid stacks that contain soon-needed boxes
    for (int b : dest_stack) {
        if (b >= next_target && b < next_target + W) {
            score += 1.0;
        }
    }

    // Bonus: if the bottom of our block continues a sorted run on dest
    if (!dest_stack.empty() && !block.empty()) {
        int top_of_dest = dest_stack.back();
        int bottom_of_block = block[0];
        // If bottom_of_block > top_of_dest, we're maintaining some order
        // Not critical but slight bonus
        if (bottom_of_block > top_of_dest && top_of_dest > next_target) {
            score -= 0.5;
        }
    }

    // Empty stack bonus - preserve empty stacks as buffers
    if (dest_stack.empty()) {
        score -= 2.0; // slight bonus for using empty stack (flexible)
        // But also penalty if block is large (wastes buffer)
        if (block.size() > 5) score += 1.0;
    }

    return score;
}

int best_dest_for_block(const State& s, const std::vector<int>& block, int src_stack, int next_target, int lookahead) {
    double best_score = 1e18;
    int best_dest = -1;
    for (int d = 0; d < s.M; d++) {
        if (d == src_stack) continue;
        double sc = evaluate_placement(s, block, d, next_target, lookahead);
        if (sc < best_score) {
            best_score = sc;
            best_dest = d;
        }
    }
    return best_dest;
}

struct Operation {
    int box_val; // 0-indexed
    int dest;    // 0-indexed for move, -1 for carry-out
};

struct Solution {
    long long energy;
    std::vector<Operation> ops;
};

// Run greedy simulation with split decisions
// decisions[k] = {split_point, dest1, dest2} for each target k
// split_point = h means no split (move all h boxes to dest1)
// split_point < h means split: move top (h - split_point) to dest1, then bottom split_point to dest2
struct Decision {
    int split_point; // 0 = no boxes above (just carry out), h = all to dest1, else split
    int dest1; // destination for first (top) group
    int dest2; // destination for second (bottom) group, only used if split
};

Solution run_with_decisions(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           const std::vector<Decision>& decisions, bool record_ops) {
    State s;
    s.init(N, M, init_stacks);
    std::vector<Operation> ops;
    if (record_ops) ops.reserve(N * 3);

    for (int k = 0; k < N; k++) {
        int h = s.boxes_above(k);
        if (h == 0) {
            s.carry_out(k);
            if (record_ops) ops.push_back({k, -1});
            continue;
        }

        const Decision& dec = decisions[k];
        int src = s.box_stack[k];
        int height_of_target = s.box_height[k];

        if (dec.split_point >= h || dec.split_point <= 0) {
            // No split: move all boxes above to dest1
            int first_box_above = s.stacks[src][height_of_target + 1];
            int actual_dest = dec.dest1;
            if (actual_dest == src || actual_dest < 0 || actual_dest >= M) {
                actual_dest = (src + 1) % M;
            }
            s.move(first_box_above, actual_dest);
            if (record_ops) ops.push_back({first_box_above, actual_dest});
        } else {
            // Split: move top group first, then bottom group
            int sp = dec.split_point; // bottom group has sp boxes, top group has h-sp boxes
            // Top group starts at height_of_target + sp + 1
            int top_group_first = s.stacks[src][height_of_target + sp + 1];
            int actual_dest1 = dec.dest1;
            if (actual_dest1 == src || actual_dest1 < 0 || actual_dest1 >= M) {
                actual_dest1 = (src + 1) % M;
            }
            s.move(top_group_first, actual_dest1);
            if (record_ops) ops.push_back({top_group_first, actual_dest1});

            // Bottom group starts at height_of_target + 1
            int bottom_group_first = s.stacks[src][height_of_target + 1];
            int actual_dest2 = dec.dest2;
            if (actual_dest2 == src || actual_dest2 < 0 || actual_dest2 >= M) {
                actual_dest2 = (src + 1) % M;
            }
            if (actual_dest2 == src) {
                actual_dest2 = (src + 2) % M;
            }
            s.move(bottom_group_first, actual_dest2);
            if (record_ops) ops.push_back({bottom_group_first, actual_dest2});
        }

        s.carry_out(k);
        if (record_ops) ops.push_back({k, -1});
    }

    return {s.energy, std::move(ops)};
}

// Generate initial decisions using greedy heuristic with split evaluation
std::vector<Decision> generate_greedy_decisions(const std::vector<std::vector<int>>& init_stacks, int N, int M, int lookahead) {
    State s;
    s.init(N, M, init_stacks);
    std::vector<Decision> decisions(N);

    for (int k = 0; k < N; k++) {
        int h = s.boxes_above(k);
        if (h == 0) {
            decisions[k] = {0, 0, 0};
            s.carry_out(k);
            continue;
        }

        int src = s.box_stack[k];
        int height_of_target = s.box_height[k];

        // Option A: No split - move all h boxes to best destination
        std::vector<int> full_block(s.stacks[src].begin() + height_of_target + 1, s.stacks[src].end());
        int best_dest_nosplit = best_dest_for_block(s, full_block, src, k + 1, lookahead);
        double cost_nosplit = (double)(h + 1) + evaluate_placement(s, full_block, best_dest_nosplit, k + 1, lookahead);

        // Option B: Try splits
        int best_sp = h; // default = no split
        int best_d1 = best_dest_nosplit, best_d2 = 0;
        double best_cost = cost_nosplit;

        if (h >= 2) {
            // Try a few split points
            int step = std::max(1, h / 6);
            for (int sp = step; sp < h; sp += step) {
                // bottom group: [height_of_target+1 ... height_of_target+sp] (sp boxes)
                // top group: [height_of_target+sp+1 ... end] (h-sp boxes)
                std::vector<int> top_group(s.stacks[src].begin() + height_of_target + sp + 1, s.stacks[src].end());
                std::vector<int> bottom_group(s.stacks[src].begin() + height_of_target + 1, s.stacks[src].begin() + height_of_target + sp + 1);

                // Find best dest for top group
                int d1 = best_dest_for_block(s, top_group, src, k + 1, lookahead);
                // Find best dest for bottom group (considering top group already placed)
                // Simplified: just find best dest excluding src
                int d2 = best_dest_for_block(s, bottom_group, src, k + 1, lookahead);
                // Slight adjustment: prefer d2 != d1 if possible
                if (d2 == d1) {
                    double best_alt_score = 1e18;
                    int alt_d2 = d2;
                    for (int dd = 0; dd < M; dd++) {
                        if (dd == src || dd == d1) continue;
                        double sc = evaluate_placement(s, bottom_group, dd, k + 1, lookahead);
