            if (actual_d1 == src) actual_d1 = (src + 1) % M;
            s.move(top_first, actual_d1);

            int bottom_first = s.stacks[src][height_of_target + 1];
            int actual_d2 = best_d2;
            if (actual_d2 == src) actual_d2 = (src + 1) % M;
            if (actual_d2 == src) actual_d2 = (src + 2) % M;
            s.move(bottom_first, actual_d2);
        }
        s.carry_out(k);
    }

    return decisions;
}

// SA to optimize decisions
void optimize_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                 std::vector<Decision>& decisions, long long& best_energy) {

    double t_start = elapsed();
    double time_budget = TIME_LIMIT_SECONDS - t_start - 0.05;
    if (time_budget <= 0.01) return;

    double T_initial = 50.0;
    double T_final = 0.1;

    // Current solution
    std::vector<Decision> current_decisions = decisions;
    long long current_energy = run_with_decisions(init_stacks, N, M, current_decisions, false).energy;
    best_energy = current_energy;
    decisions = current_decisions;

    int iterations = 0;

    while (true) {
        double now = elapsed();
        if (now >= TIME_LIMIT_SECONDS - 0.05) break;

        double progress = (now - t_start) / time_budget;
        if (progress > 1.0) break;
        double T = T_initial * std::pow(T_final / T_initial, progress);

        // Make a perturbation
        std::vector<Decision> new_decisions = current_decisions;

        int op_type = rng.randint(0, 99);

        if (op_type < 40) {
            // Change destination of a random step
            int k = rng.randint(0, N - 1);
            if (new_decisions[k].split_point > 0 && new_decisions[k].split_point < 200) {
                // Has a move; change dest1 or dest2
                if (rng.randint(0, 1) == 0 || new_decisions[k].split_point >= 200) {
                    new_decisions[k].dest1 = rng.randint(0, M - 1);
                } else {
                    new_decisions[k].dest2 = rng.randint(0, M - 1);
                }
            } else if (new_decisions[k].split_point == 0) {
                // No boxes above; nothing to change, try another
                continue;
            } else {
                new_decisions[k].dest1 = rng.randint(0, M - 1);
            }
        } else if (op_type < 60) {
            // Toggle split on/off for a step
            int k = rng.randint(0, N - 1);
            // We need to know how many boxes are above at step k
            // Since we don't easily know h without simulating, just try a random split_point
            if (new_decisions[k].split_point > 0) {
                // Currently has boxes above
                if (new_decisions[k].split_point >= 100) {
                    // Large = no split; try introducing a split
                    new_decisions[k].split_point = rng.randint(1, 10);
                    new_decisions[k].dest2 = rng.randint(0, M - 1);
                } else {
                    // Currently splitting; try removing split
                    if (rng.randint(0, 1) == 0) {
                        new_decisions[k].split_point = 200; // no split sentinel
                    } else {
                        // Change split point
                        new_decisions[k].split_point = rng.randint(1, 15);
                    }
                }
            }
        } else if (op_type < 85) {
            // Block change: randomize a few consecutive decisions
            int k_start = rng.randint(0, N - 1);
            int len = rng.randint(1, std::max(1, N / 15));
            for (int i = 0; i < len; i++) {
                int k = (k_start + i) % N;
                new_decisions[k].dest1 = rng.randint(0, M - 1);
                if (new_decisions[k].split_point > 0 && new_decisions[k].split_point < 100) {
                    new_decisions[k].dest2 = rng.randint(0, M - 1);
                }
            }
        } else {
            // Change split point for a random step
            int k = rng.randint(0, N - 1);
            if (new_decisions[k].split_point > 0) {
                new_decisions[k].split_point = rng.randint(1, 19);
                new_decisions[k].dest1 = rng.randint(0, M - 1);
                new_decisions[k].dest2 = rng.randint(0, M - 1);
            }
        }

        long long new_energy = run_with_decisions(init_stacks, N, M, new_decisions, false).energy;

        long long delta = new_energy - current_energy;
        if (delta < 0 || (T > 1e-9 && rng.randdbl() < std::exp(-(double)delta / T))) {
            current_energy = new_energy;
            current_decisions = new_decisions;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                decisions = new_decisions;
            }
        }

        iterations++;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--; // 0-indexed
        }
    }

    // Generate initial greedy decisions
    int lookahead = 15;
    std::vector<Decision> decisions = generate_greedy_decisions(init_stacks, N, M, lookahead);

    // Evaluate initial
    long long best_energy = run_with_decisions(init_stacks, N, M, decisions, false).energy;

    // Also try without splits (all no-split) using simple greedy
    std::vector<Decision> nosplit_decisions(N);
    {
        State s;
        s.init(N, M, init_stacks);
        for (int k = 0; k < N; k++) {
            int h = s.boxes_above(k);
            if (h == 0) {
                nosplit_decisions[k] = {0, 0, 0};
                s.carry_out(k);
                continue;
            }
            int src = s.box_stack[k];
            int height_of_target = s.box_height[k];
            std::vector<int> block(s.stacks[src].begin() + height_of_target + 1, s.stacks[src].end());
            int bd = best_dest_for_block(s, block, src, k + 1, lookahead);
            nosplit_decisions[k] = {200, bd, 0}; // 200 = no split sentinel (>= h always)
            int first_box_above = s.stacks[src][height_of_target + 1];
            int actual_dest = bd;
            if (actual_dest == src) actual_dest = (src + 1) % M;
            s.move(first_box_above, actual_dest);
            s.carry_out(k);
        }
    }
    long long nosplit_energy = run_with_decisions(init_stacks, N, M, nosplit_decisions, false).energy;
    if (nosplit_energy < best_energy) {
        best_energy = nosplit_energy;
        decisions = nosplit_decisions;
    }

    // SA optimization
    optimize_sa(init_stacks, N, M, decisions, best_energy);

    // Output final solution
    Solution sol = run_with_decisions(init_stacks, N, M, decisions, true);
    for (const auto& op : sol.ops) {
        if (op.dest == -1) {
            std::cout << (op.box_val + 1) << " 0\n";
        } else {
            std::cout << (op.box_val + 1) << " " << (op.dest + 1) << "\n";
        }
    }

